import re
d_str=json.dumps(d,ensure_ascii=False).replace('Хватit','Хватит')
d=json.loads(d_str)
json.dump(d,open('src/main/resources/static/scenarios/level-5-1.json','w',encoding='utf-8'),ensure_ascii=False,indent=2)
E=d['events']
print(f"✓ level-5-1.json: {len(E)} событий")
ok=True
for k,e in E.items():
    for s in ['left','right','a','b']:
        t=e.get(s,{}).get('to')
        if t and t!='__resolve__' and t not in E: print(f"  ✗ {k}.{s}"); ok=False
    if e.get('next') and e['next'] not in E: print(f"  ✗ {k}.next"); ok=False
if ok: print("  ✓ переходы валидны")
for k,e in E.items():
    for f in ['text','dialogue','intro','react']:
        if str(e.get(f,'')).count('«')!=str(e.get(f,'')).count('»'): print(f"  ⚠ {k}.{f} кавычки")
full=json.dumps(d,ensure_ascii=False)
print(f"  иероглифы: {len(re.findall('['+chr(0x4e00)+'-'+chr(0x9fff)+']',full))}")
print(f"  латиница в тексте: {'Хватit' in full}")
for pat in ['нутром чу','дожд','чует неладн','спиной чу','малыш']:
    c=sum(len(re.findall(pat,str(e.get(f,'')),re.I)) for e in E.values() for f in ['text','dialogue','intro','react'])
    if c: print(f"  ⚠ '{pat}': {c}")

