import json
path="src/main/resources/static/scenarios/campaign.json"
d=json.load(open(path,encoding='utf-8'))
adds=[('level-4-3',{'id':'level-5-1','chapter':5,'title':'Усадьба','subtitle':'Дом-музей'}),
      ('level-5-1',{'id':'level-5-2','chapter':5,'title':'Усадьба','subtitle':'Коллекционер'}),
      ('level-5-2',{'id':'level-5-3','chapter':5,'title':'Усадьба','subtitle':'Цена'}),
      ('level-5-3',{'id':'level-5-4','chapter':5,'title':'Усадьба','subtitle':'Эпилог'})]
for after,item in adds:
    if item['id'] in [c['id'] for c in d['cases']]: continue
    new=[]
    for c in d['cases']:
        new.append(c)
        if c['id']==after: new.append(item)
    d['cases']=new
# убираем старый case005 (Последняя Выставка) — заменён главой 5
d['cases']=[c for c in d['cases'] if c['id']!='case005']
json.dump(d,open(path,'w',encoding='utf-8'),ensure_ascii=False,indent=2)
print("  глава 5 подключена, case005 убран")
print("  ВСЕГО УРОВНЕЙ:", len(d['cases']))
